/// <reference path="../pb_data/types.d.ts" />
migrate((app) => {
    // Create the game_scores collection
    const collection = new Collection({
        name: "game_scores",
        type: "base",
        listRule: "",
        viewRule: "",
        createRule: "",
        updateRule: null,
        deleteRule: null,
        fields: [
            {
                name: "score",
                type: "number",
                required: false,
            },
        ],
    });

    app.save(collection);
}, (app) => {
    // Down: delete the collection
    const collection = app.findCollectionByNameOrId("game_scores");
    app.delete(collection);
});

/// <reference path="../pb_data/types.d.ts" />

routerAdd("GET", "/api/stats", (e) => {
    const db = $app.db();

    const result = new DynamicModel({
        total_count: 0,
        total_score: 0,
    });

    db.newQuery(
        "SELECT count(id) as total_count, COALESCE(sum(score), 0) as total_score FROM game_scores"
    ).one(result);

    return e.json(200, {
        count: result.get("total_count"),
        sum:   result.get("total_score"),
    });
});
